  <div class="border border-slate-200 dark:border-slate-800 p-8 bg-white dark:bg-slate-900 shadow-[4px_4px_0px_0px_rgba(15,23,42,0.05)] flex flex-col lg:flex-row lg:items-center lg:justify-between gap-4">
    <div>
      <button (click)="goBack()" class="flex items-center gap-1 text-[10px] font-bold uppercase tracking-widest text-indigo-600 dark:text-indigo-400 mb-2">
        <span class="material-symbols-outlined text-sm">arrow_back</span>
        <span>Regresar a cursos</span>
      </button>
      <h1 class="text-2xl font-black text-slate-900 dark:text-slate-100 tracking-tight uppercase leading-none">Estudiantes Matriculados</h1>
      <p class="text-slate-500 dark:text-slate-400 text-xs mt-2" *ngIf="curso">Listado del curso: <strong class="uppercase">{{ curso.nombre }}</strong>.</p>
    </div>
    <div class="flex flex-col sm:flex-row gap-3 w-full lg:w-auto">
      <label class="flex items-center gap-2 border border-slate-200 dark:border-slate-700 px-3 py-2 bg-slate-50 dark:bg-slate-800 w-full sm:w-72">
        <span class="material-symbols-outlined text-sm text-slate-400">search</span>
        <input [(ngModel)]="searchTerm" (ngModelChange)="onSearchChange()" type="text" placeholder="Buscar alumno, correo o fecha" class="w-full bg-transparent outline-none text-sm">
      </label>
      <button (click)="toggleDateSort()" class="px-4 py-2 border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-xs font-bold uppercase tracking-widest flex items-center gap-2">
        <span class="material-symbols-outlined text-sm">schedule</span>
        <span>Fecha {{ dateSortOrder === 'desc' ? '↓' : '↑' }}</span>
      </button>
    </div>
  </div>

  <div *ngIf="isLoading" class="flex flex-col items-center justify-center p-20 border border-slate-200 dark:border-slate-800 bg-white dark:bg-slate-900">
    <span class="animate-spin inline-block w-8 h-8 border-4 border-indigo-600 dark:border-indigo-400 border-t-transparent rounded-full mb-3"></span>
    <span class="text-xs font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest">Cargando listado de alumnos...</span>
  </div>

  <div *ngIf="!isLoading && filteredEstudiantes.length === 0" class="border border-slate-200 dark:border-slate-800 p-12 text-center bg-white dark:bg-slate-900">
    <span class="material-symbols-outlined text-5xl text-slate-300 dark:text-slate-800 mb-2">group_off</span>
    <h3 class="text-sm font-bold text-slate-800 dark:text-slate-200 uppercase">Sin resultados</h3>
    <p class="text-slate-500 dark:text-slate-400 text-xs mt-1.5 max-w-sm mx-auto">No encontramos estudiantes con esos criterios.</p>
  </div>

  <div *ngIf="!isLoading && pagedEstudiantes.length > 0" class="border border-slate-200 dark:border-slate-800 bg-white dark:bg-slate-900 shadow-[4px_4px_0px_0px_rgba(15,23,42,0.05)] overflow-hidden">
    <div class="overflow-x-auto">
      <table class="w-full text-left border-collapse">
        <thead>
          <tr class="bg-slate-50 dark:bg-slate-800/40 border-b border-slate-200 dark:border-slate-800 text-[10px] font-black text-slate-500 dark:text-slate-400 uppercase tracking-wider">
            <th class="py-4 px-6">Alumno</th>
            <th class="py-4 px-6">Correo</th>
            <th class="py-4 px-6">Progreso</th>
            <th class="py-4 px-6">Estado</th>
            <th class="py-4 px-6">Última Actividad</th>
          </tr>
        </thead>
        <tbody class="divide-y divide-slate-100 dark:divide-slate-800 text-xs">
          <tr *ngFor="let estudiante of pagedEstudiantes" class="hover:bg-slate-50/50 dark:hover:bg-slate-800/50 transition-colors duration-200">
            <td class="py-4 px-6 font-bold text-slate-900 dark:text-white uppercase">{{ estudiante.nombres }} {{ estudiante.apellidos }}</td>
            <td class="py-4 px-6 text-slate-500 dark:text-slate-400 font-mono">{{ estudiante.correo }}</td>
            <td class="py-4 px-6">
              <div class="flex items-center gap-3 min-w-[150px]">
                <div class="flex-grow bg-slate-200 dark:bg-slate-800 h-1.5 overflow-hidden">
                  <div class="bg-slate-900 dark:bg-slate-100 h-full" [style.width.%]="estudiante.porcentajeAvance"></div>
                </div>
                <span class="font-bold text-slate-900 dark:text-white font-mono">{{ estudiante.porcentajeAvance }}%</span>
              </div>
            </td>
            <td class="py-4 px-6">
              <span [ngClass]="{
                'bg-emerald-50 text-emerald-700 border-emerald-200 dark:bg-emerald-950/30 dark:text-emerald-400 dark:border-emerald-900/60': estudiante.completado,
                'bg-slate-100 text-slate-500 border-slate-200 dark:bg-slate-800 dark:text-slate-400 dark:border-slate-700': !estudiante.completado
              }" class="text-[9px] font-black uppercase tracking-widest border px-2 py-0.5">
                {{ estudiante.completado ? 'Completado' : 'En Curso' }}
              </span>
            </td>
            <td class="py-4 px-6 text-slate-400 dark:text-slate-500">{{ estudiante.fechaActualizacion | date:'dd/MM/yyyy HH:mm' }}</td>
          </tr>
        </tbody>
      </table>
    </div>
  </div>

  <div *ngIf="!isLoading && totalPages > 1" class="flex items-center justify-between border border-slate-200 dark:border-slate-800 bg-white dark:bg-slate-900 px-4 py-3">
    <p class="text-xs font-bold uppercase tracking-widest text-slate-500">Página {{ currentPage }} de {{ totalPages }}</p>
    <div class="flex items-center gap-2">
      <button (click)="previousPage()" [disabled]="currentPage === 1" class="px-3 py-2 border text-xs font-bold uppercase disabled:opacity-40">Anterior</button>
      <button (click)="nextPage()" [disabled]="currentPage === totalPages" class="px-3 py-2 border text-xs font-bold uppercase disabled:opacity-40">Siguiente</button>
    </div>
  </div>
</div>
